import { ArbitrageStats } from '@/components/arbitrage/ArbitrageStats';
import { ArbitrageFilters } from '@/components/arbitrage/ArbitrageFilters';
import { ArbitrageListWithPins } from '@/app/arbitrage/ArbitrageListWithPins';
import { EmptyState } from '@/components/ui/EmptyState';
import type { ArbitrageOpportunitiesResponse } from '@/app/api/arbitrage/opportunities/route';

const baseUrl =
  process.env.NEXT_PUBLIC_URL ??
  (process.env.VERCEL_URL ? `https://${process.env.VERCEL_URL}` : 'http://localhost:3000');

interface ArbitragePageProps {
  searchParams: Promise<{
    minRoi?: string;
    category?: string;
    sort?: 'roi' | 'volume' | 'newest';
  }>;
}

export default async function ArbitragePage({ searchParams }: ArbitragePageProps) {
  const params = await searchParams;
  const minRoi = parseFloat(params.minRoi ?? '0.01');
  const category = params.category ?? undefined;
  const sort = params.sort ?? 'roi';

  const data = await fetch(
    `${baseUrl}/api/arbitrage/opportunities?minRoi=${minRoi}&sort=${sort}&limit=20${category ? `&category=${encodeURIComponent(category)}` : ''}`,
    { cache: 'no-store' }
  )
    .then((r) => r.json())
    .catch(() => ({
      opportunities: [],
      count: 0,
      scannedPairs: 0,
      generatedAt: new Date().toISOString()
    }));

  console.log('[Arbitrage Page] opportunities count:', data?.opportunities?.length);

  const opportunities = data.opportunities ?? [];
  const count = data.count ?? 0;
  const scannedPairs = data.scannedPairs ?? 0;
  const generatedAt = data.generatedAt ?? new Date().toISOString();

  const avgRoi =
    opportunities.length > 0
      ? opportunities.reduce((s, o) => s + o.roi, 0) / opportunities.length
      : 0;
  const bestRoi =
    opportunities.length > 0 ? Math.max(...opportunities.map((o) => o.roi)) : 0;

  return (
    <div className="container px-4 py-8">
      <ArbitrageStats
        count={count}
        avgRoi={avgRoi}
        bestRoi={bestRoi}
        scannedPairs={scannedPairs}
        generatedAt={generatedAt}
      />

      <div className="mt-8">
        <ArbitrageFilters
          currentMinRoi={minRoi * 100}
          currentCategory={category}
          currentSort={sort}
          totalResults={count}
        />
      </div>

      <div className="mt-6">
        {opportunities.length > 0 ? (
          <ArbitrageListWithPins opportunities={opportunities} />
        ) : (
          <EmptyState
            icon="🔍"
            title="No arbitrage opportunities found"
            description="The market is currently efficient. Check back soon — opportunities appear and disappear within minutes."
            action={{
              label: 'Reduce Min ROI filter',
              href: '/arbitrage?minRoi=0.005'
            }}
            secondaryAction={{
              label: 'View All Markets',
              href: '/search'
            }}
          />
        )}
      </div>

      <p className="mt-8 text-center text-xs text-muted-foreground">
        Last updated: {new Date(generatedAt).toLocaleString()}
      </p>
    </div>
  );
}
